source_code:
int write_passwd(const struct _node* passwd, const char* file) {
    FILE*	output;

    if (opt_verbose>2)
	printf("Writing passwd-file to %s\n", file);

    /* Delete possible left-over file */
    (void) unlink(file);

    if (selinux_prepare_create_file(sys_passwd) != 0) {
        return 0;
    }

    output = fopen(file, "wx");

    selinux_after_create_file();

    if (output == NULL) {
	fprintf(stderr, "Failed to open passwd-file %s for writing: %s\n",
		file, strerror(errno));
	return 0;
    }

    for (;passwd; passwd=passwd->next) {
	assert(passwd->t==t_passwd);
	if (fputpwent(&(passwd->d.pw), output)!=0) {
	    fprintf(stderr, "Error writing passwd-entry: %s\n", strerror(errno));
	    return 0;
	}
    }

    if (fclose(output)!=0) {
	fprintf(stderr, "Error closing passwd-file %s: %s\n", file, strerror(errno));
	return 0;
    }

    return 1;
}

